MAP
  NAME "guardian"
  EXTENT -180 -90 180 90
  IMAGETYPE png

  PROJECTION
    "init=epsg:4326"
  END

  WEB
    METADATA
      "wms_title" "Guardian WMS"
      "wms_onlineresource" "http://localhost:8081/?map=guardian&"
      "wms_srs" "EPSG:4326 EPSG:3857"
      "wms_enable_request" "*"
    END
  END

  LAYER
    NAME "ndvi"
    TYPE RASTER
    STATUS ON
    DATA "/data/ndvi.tif"

    PROCESSING "SCALE=-0.1,1.0"

    PROJECTION
      "init=epsg:4326"
    END
    
    METADATA
      "wms_title" "NDVI"
      "wms_srs" "EPSG:4326 EPSG:3857"
    END

    CLASS
      EXPRESSION ([pixel] >= 0 AND [pixel] < 0.2)
      STYLE
        COLOR 255 255 0
      END
    END

    CLASS
      EXPRESSION ([pixel] >= 0.2 AND [pixel] < 0.4)
      STYLE
        COLOR 255 165 0
      END
    END

    CLASS
      EXPRESSION ([pixel] >= 0.4 AND [pixel] < 0.6)
      STYLE
        COLOR 144 238 144
      END
    END

    CLASS
      EXPRESSION ([pixel] >= 0.6)
      STYLE
        COLOR 0 128 0
      END
    END
  END

  LAYER
    NAME "municipality"
    TYPE POLYGON
    STATUS ON

    CONNECTIONTYPE POSTGIS
    CONNECTION "host=host.docker.internal port=5435 dbname=geoespatial_2026_prod user=postgres password='aODBg7BZwLkB+%7ct]2gnWdGl![M,L'"

    DATA "geometry FROM (SELECT id, geometry FROM gf.municipality WHERE active = true LIMIT 20) AS municipality USING UNIQUE id USING SRID=4326"

    PROJECTION
      "init=epsg:4326"
    END

    METADATA
      "wms_title" "Municipality"
      "wms_srs" "EPSG:4326 EPSG:3857"
    END

    CLASS
      STYLE
        COLOR 255 255 255
        OPACITY 20
        OUTLINECOLOR 255 0 0
        WIDTH 2
      END
    END
  END

  LAYER
    NAME "selected_municipality"
    TYPE POLYGON
    STATUS ON

    CONNECTIONTYPE POSTGIS
    CONNECTION "host=host.docker.internal port=5435 dbname=geoespatial_2026_prod user=postgres password='aODBg7BZwLkB+%7ct]2gnWdGl![M,L'"

    DATA "geometry FROM (SELECT id, geometry FROM gf.municipality WHERE id = 262) AS selected_municipality USING UNIQUE id USING SRID=4326"

    PROJECTION
      "init=epsg:4326"
    END

    METADATA
      "wms_title" "Selected Municipality"
      "wms_srs" "EPSG:4326 EPSG:3857"
    END

    CLASS
      STYLE
        COLOR 255 0 0
        OPACITY 30
        OUTLINECOLOR 255 0 0
        WIDTH 4
      END
    END
  END

  LAYER
    NAME "satellite"
    TYPE RASTER
    STATUS ON

    CONNECTIONTYPE WMS

    CONNECTION "https://gibs.earthdata.nasa.gov/wms/epsg4326/best/wms.cgi?"

    METADATA
      "wms_name" "BlueMarble_ShadedRelief"
      "wms_server_version" "1.3.0"
      "wms_srs" "EPSG:4326"
      "wms_format" "image/jpeg"
    END

    PROJECTION
      "init=epsg:4326"
    END
  END

END